using UnityEngine;
using Climbing;

public class FinalAlignmentFix
{
    public static string Run()
    {
        ClimbController cc = Object.FindObjectOfType<ClimbController>();
        if (cc == null) return "No player found in scene.";

        GameObject pm = cc.gameObject;
        pm.transform.localPosition = Vector3.zero;

        return $"Successfully reset {pm.name} local position to Zero. It was previously at 1.01 Y.";
    }
}
